sources.content:
plugins {
    id 'jacoco'
    id 'com.diffplug.spotless' version '8.4.0'
    id 'com.vanniktech.maven.publish' version '0.36.0' apply false
    id 'io.github.gradle-nexus.publish-plugin' version '2.0.0'
}

project.version = "0.3.0-SNAPSHOT"

repositories {
    mavenCentral()
}

jacoco {
    toolVersion = '0.8.14'
}

allprojects {
    group = 'com.datadoghq'
    version = rootProject.version
}

nexusPublishing {
    repositories {
        sonatype {
            nexusUrl = uri('https://ossrh-staging-api.central.sonatype.com/service/local/')
            snapshotRepositoryUrl = uri('https://central.sonatype.com/repository/maven-snapshots/')
            username = System.getenv('SONATYPE_USERNAME')
            password = System.getenv('SONATYPE_PASSWORD')
        }
    }
}

// Configure Maven Central publishing for all publishable subprojects
subprojects {
    plugins.withId('com.vanniktech.maven.publish') {
        mavenPublishing {
            publishToMavenCentral()
            signAllPublications()

            pom {
                name = project.name
                description = project.description ?: "Part of the Reggie project"
                url = 'https://github.com/DataDog/java-reggie'
                licenses {
                    license {
                        name = 'The Apache License, Version 2.0'
                        url = 'http://www.apache.org/licenses/LICENSE-2.0.txt'
                    }
                }
                developers {
                    developer {
                        id = 'DataDog'
                        name = 'Datadog'
                        email = 'oss@datadoghq.com'
                    }
                }
                scm {
                    connection = 'scm:git:git://github.com/DataDog/java-reggie.git'
                    developerConnection = 'scm:git:ssh://github.com/DataDog/java-reggie.git'
                    url = 'https://github.com/DataDog/java-reggie'
                }
            }
        }
        def gpgKeyProvider = providers.environmentVariable("GPG_PRIVATE_KEY")
        def gpgPasswordProvider = providers.environmentVariable("GPG_PASSWORD")
        signing {
            useInMemoryPgpKeys(gpgKeyProvider.orNull, gpgPasswordProvider.orNull)
        }
        tasks.withType(Sign).configureEach {
            onlyIf { gpgKeyProvider.isPresent() }
        }
    }
}

subprojects {
    apply plugin: 'java'
    apply plugin: 'jacoco'
    apply plugin: 'com.diffplug.spotless'

    repositories {
        mavenCentral()
    }

    java {
        toolchain {
            languageVersion = JavaLanguageVersion.of(21)
        }
    }

    spotless {
        java {
            target 'src/**/*.java'

            // Use Google Java Format
            googleJavaFormat('1.35.0')

            // Exclude generated sources
            targetExclude 'build/generated/**'

            // Check for Apache 2.0 license header
            licenseHeaderFile rootProject.file('.github/license-header.txt')
        }
    }

    jacoco {
        toolVersion = '0.8.14'
    }

    tasks.withType(Javadoc).configureEach {
        options.addStringOption('Xdoclint:none', '-quiet')
    }

    tasks.named('test') {
        finalizedBy jacocoTestReport
    }

    tasks.named('jacocoTestReport') {
        dependsOn test
        reports {
            xml.required = true
            html.required = true
            csv.required = false
        }
    }

    // Set artifact ID to match project name
    // This ensures artifact IDs match the project name (e.g. reggie-processor).
    tasks.withType(Jar) {
        archiveBaseName = project.name
    }
}

// Aggregate coverage report for all modules (excluding benchmarks and test infrastructure)
tasks.register('jacocoAggregateReport', JacocoReport) {
    group = 'verification'
    description = 'Generates aggregate JaCoCo coverage report'

    dependsOn subprojects*.test

    // Collect execution data from all subprojects except benchmark
    subprojects.each { subproject ->
        if (subproject.name != 'reggie-benchmark') {
            subproject.plugins.withType(JavaPlugin) {
                executionData subproject.tasks.withType(Test)
                sourceSets subproject.sourceSets.main
            }
        }
    }

    // Exclude test data, corpus, debug packages, and standalone debug utilities
    classDirectories.setFrom(files(classDirectories.files.collect {
        fileTree(dir: it, exclude: [
            '**/testdata/**',
            '**/corpus/**',
            '**/debug/**',
            '**/PatternDebugger.class'
        ])
    }))

    reports {
        xml.required = true
        xml.outputLocation = layout.buildDirectory.file('reports/jacoco/aggregate/jacocoTestReport.xml')
        html.required = true
        html.outputLocation = layout.buildDirectory.dir('reports/jacoco/aggregate/html')
    }
}

// Coverage verification with module-specific thresholds (excluding benchmarks and test infrastructure)
tasks.register('jacocoVerify', JacocoCoverageVerification) {
    group = 'verification'
    description = 'Verifies code coverage meets minimum thresholds'

    dependsOn subprojects*.test

    violationRules {
        rule {
            limit {
                minimum = 0.70  // 70% overall minimum
            }
        }
    }

    // Collect execution data from all subprojects except benchmark
    subprojects.each { subproject ->
        if (subproject.name != 'reggie-benchmark') {
            subproject.plugins.withType(JavaPlugin) {
                executionData subproject.tasks.withType(Test)
                sourceSets subproject.sourceSets.main
            }
        }
    }

    // Exclude test data, corpus, debug packages, and standalone debug utilities
    classDirectories.setFrom(files(classDirectories.files.collect {
        fileTree(dir: it, exclude: [
            '**/testdata/**',
            '**/corpus/**',
            '**/debug/**',
            '**/PatternDebugger.class'
        ])
    }))
}
